package org.apache.flink.streaming.api.windowing.assigners;

import org.apache.flink.annotation.PublicEvolving;
import org.apache.flink.api.common.ExecutionConfig;
import org.apache.flink.api.common.typeutils.TypeSerializer;
import org.apache.flink.streaming.api.windowing.triggers.EventTimeTrigger;
import org.apache.flink.streaming.api.windowing.triggers.Trigger;
import org.apache.flink.streaming.api.windowing.windows.TimeWindow;

import java.time.Instant;
import java.time.LocalDate;
import java.time.LocalTime;
import java.time.ZoneId;
import java.time.ZonedDateTime;
import java.util.Collection;
import java.util.Collections;

/**
 * A {@link WindowAssigner} that groups trading events into windows aligned with market session
 * boundaries (e.g., NYSE 09:30-16:00 ET, LSE 08:00-16:30 GMT) rather than fixed time intervals.
 *
 * <p>Each element is assigned to a {@link TimeWindow} whose start and end correspond to the
 * configured market session open and close times for the calendar day of the element's timestamp.
 * Overlapping windows (e.g., from late-arriving events) are merged via {@link
 * TimeWindow#mergeWindows}.
 *
 * <p>Overnight sessions (where {@code close} is before {@code open} in wall-clock time, e.g.,
 * futures markets) are handled by spanning the window across midnight: the session is considered to
 * have opened at {@code open} on day D and closed at {@code close} on day D+1.
 *
 * <p>Example usage for NYSE:
 *
 * <pre>{@code
 * DataStream<TradeEvent> trades = ...;
 * trades.keyBy(TradeEvent::getSymbol)
 *       .window(PricingSessionWindow.forMarket(
 *           "NYSE",
 *           ZoneId.of("America/New_York"),
 *           LocalTime.of(9, 30),
 *           LocalTime.of(16, 0)))
 *       .aggregate(...);
 * }</pre>
 */
@PublicEvolving
public class PricingSessionWindow extends MergingWindowAssigner<Object, TimeWindow> {

    private static final long serialVersionUID = 1L;

    /** Human-readable identifier for the market (e.g., "NYSE", "LSE"). */
    private final String marketId;

    /** Time zone in which session open/close times are expressed. */
    private final ZoneId timezone;

    /** Wall-clock time at which the trading session opens each day. */
    private final LocalTime sessionOpen;

    /** Wall-clock time at which the trading session closes each day. */
    private final LocalTime sessionClose;

    protected PricingSessionWindow(
            String marketId, ZoneId timezone, LocalTime sessionOpen, LocalTime sessionClose) {
        this.marketId = marketId;
        this.timezone = timezone;
        this.sessionOpen = sessionOpen;
        this.sessionClose = sessionClose;
    }

    /**
     * Creates a new {@code PricingSessionWindow} for the given market.
     *
     * @param marketId Human-readable market identifier (e.g., "NYSE", "LSE").
     * @param timezone The time zone in which {@code open} and {@code close} are expressed.
     * @param open The daily session open time in the given {@code timezone}.
     * @param close The daily session close time in the given {@code timezone}. If {@code close} is
     *     before {@code open}, the session is treated as an overnight session spanning midnight.
     * @return A {@code PricingSessionWindow} assigner for the specified market.
     */
    public static PricingSessionWindow forMarket(
            String marketId, ZoneId timezone, LocalTime open, LocalTime close) {
        return new PricingSessionWindow(marketId, timezone, open, close);
    }

    /**
     * Assigns the element to a {@link TimeWindow} representing the trading session that contains
     * the event timestamp.
     *
     * <p>For regular sessions (close &gt; open): the window covers [open, close) on the same
     * calendar day as the event.
     *
     * <p>For overnight sessions (close &lt;= open): the window covers [open on day D, close on day
     * D+1). Events arriving between midnight and session close are assigned to the window that
     * opened on day D-1.
     */
    @Override
    public Collection<TimeWindow> assignWindows(
            Object element, long timestamp, WindowAssignerContext context) {
        ZonedDateTime eventDateTime = Instant.ofEpochMilli(timestamp).atZone(timezone);
        LocalDate eventDate = eventDateTime.toLocalDate();
        LocalTime eventLocalTime = eventDateTime.toLocalTime();

        LocalDate sessionStartDate;
        if (isOvernightSession()) {
            // For overnight sessions, events between midnight and sessionClose belong to
            // the session that opened on the previous calendar day.
            if (eventLocalTime.isBefore(sessionClose)) {
                sessionStartDate = eventDate.minusDays(1);
            } else {
                sessionStartDate = eventDate;
            }
        } else {
            sessionStartDate = eventDate;
        }

        long windowStart =
                sessionStartDate
                        .atTime(sessionOpen)
                        .atZone(timezone)
                        .toInstant()
                        .toEpochMilli();

        LocalDate sessionEndDate =
                isOvernightSession() ? sessionStartDate.plusDays(1) : sessionStartDate;
        long windowEnd =
                sessionEndDate.atTime(sessionClose).atZone(timezone).toInstant().toEpochMilli();

        return Collections.singletonList(new TimeWindow(windowStart, windowEnd));
    }

    /** Returns {@code true} if the session spans midnight (i.e., close wall-clock &lt;= open). */
    private boolean isOvernightSession() {
        return !sessionClose.isAfter(sessionOpen);
    }

    /** Merges overlapping {@link TimeWindow}s by delegating to {@link TimeWindow#mergeWindows}. */
    @Override
    public void mergeWindows(
            Collection<TimeWindow> windows, MergingWindowAssigner.MergeCallback<TimeWindow> c) {
        TimeWindow.mergeWindows(windows, c);
    }

    @Override
    public Trigger<Object, TimeWindow> getDefaultTrigger() {
        return EventTimeTrigger.create();
    }

    @Override
    public TypeSerializer<TimeWindow> getWindowSerializer(ExecutionConfig executionConfig) {
        return new TimeWindow.Serializer();
    }

    @Override
    public boolean isEventTime() {
        return true;
    }

    @Override
    public String toString() {
        return "PricingSessionWindow(marketId="
                + marketId
                + ", timezone="
                + timezone
                + ", open="
                + sessionOpen
                + ", close="
                + sessionClose
                + ")";
    }
}

