package org.apache.flink.streaming.api.windowing.assigners;

import org.apache.flink.annotation.PublicEvolving;
import org.apache.flink.api.common.ExecutionConfig;
import org.apache.flink.api.common.typeutils.TypeSerializer;
import org.apache.flink.streaming.api.windowing.triggers.EventTimeTrigger;
import org.apache.flink.streaming.api.windowing.triggers.Trigger;
import org.apache.flink.streaming.api.windowing.windows.TimeWindow;

import java.time.Instant;
import java.time.LocalDate;
import java.time.LocalTime;
import java.time.ZoneId;
import java.time.ZonedDateTime;
import java.util.Collection;
import java.util.Collections;

/**
 * A {@link WindowAssigner} that groups trading events into windows aligned with market session
 * boundaries (e.g., NYSE 09:30-16:00 ET, LSE 08:00-16:30 GMT) rather than fixed time intervals.
 *
 * <p>Each element is assigned to a {@link TimeWindow} whose start and end correspond to the
 * configured market session open and close times for the calendar day of the element's timestamp.
 * Overlapping windows (e.g., from late-arriving events) are merged via {@link
 * TimeWindow#mergeWindows}.
 *
 * <p>Overnight sessions (where {@code close} is before {@code open} in wall-clock time, e.g.,
 * futures markets) are handled by spanning the window across midnight: the session is considered to
 * have opened at {@code open} on day D and closed at {@code close} on day D+1.
 *
 * <p>Example usage for NYSE:
 *
 * <pre>{@code
 * DataStream<TradeEvent> trades = ...;
