package org.apache.flink.streaming.api.windowing.triggers;

import org.apache.flink.annotation.PublicEvolving;
import org.apache.flink.streaming.api.windowing.assigners.PricingSessionWindow;
import org.apache.flink.streaming.api.windowing.windows.TimeWindow;

/**
 * A {@link Trigger} for use with {@link PricingSessionWindow} that fires when the watermark passes
 * the end of the market session window (i.e., the configured market close time).
 *
 * <p>This trigger mirrors the behavior of {@link EventTimeTrigger} but is specialized for trading
 * session semantics:
 *
 * <ul>
 *   <li>Fires once at market close (window end) via an event-time timer.
 *   <li>Supports early firing when configured with an early-fire timestamp (e.g., a circuit-breaker
 *       halt signal sets an early timer via {@link #registerEarlyFire}).
 *   <li>Supports window merging ({@link #canMerge()} returns {@code true}) and re-registers timers
 *       on merge.
 *   <li>{@link #clear(TimeWindow, TriggerContext)} removes all registered event-time timers.
 * </ul>
 */
@PublicEvolving
public class PricingSessionTrigger extends Trigger<Object, TimeWindow> {

    private static final long serialVersionUID = 1L;

    private PricingSessionTrigger() {}

    /**
     * Creates a new {@code PricingSessionTrigger} that fires at the end of each session window.
     */
    public static PricingSessionTrigger create() {
        return new PricingSessionTrigger();
    }

    /**
     * Registers an early-fire event-time timer at the given timestamp. This can be used to trigger
     * early window evaluation on configurable events such as circuit-breaker halts.
     *
     * @param earlyFireTimestamp The event-time timestamp at which to fire early.
     * @param ctx The trigger context used to register the timer.
     */
    public void registerEarlyFire(long earlyFireTimestamp, TriggerContext ctx) {
        ctx.registerEventTimeTimer(earlyFireTimestamp);
    }

    /**
     * On each element arrival, register an event-time timer at market close (window end). If the
     * watermark has already passed the window end, fire immediately.
     */
    @Override
    public TriggerResult onElement(
            Object element, long timestamp, TimeWindow window, TriggerContext ctx)
            throws Exception {
        if (window.maxTimestamp() <= ctx.getCurrentWatermark()) {
            // Watermark already past the window end — fire immediately.
            return TriggerResult.FIRE;
        } else {
            ctx.registerEventTimeTimer(window.maxTimestamp());
            return TriggerResult.CONTINUE;
        }
    }

    /**
     * Fires when the event-time timer reaches the window end (market close). Any other timer (e.g.,
     * an early-fire timer) also fires when its registered time is reached.
     */
    @Override
    public TriggerResult onEventTime(long time, TimeWindow window, TriggerContext ctx) {
        return time == window.maxTimestamp() ? TriggerResult.FIRE : TriggerResult.FIRE_AND_PURGE;
    }

    /** Processing-time timers are not used by this trigger. */
    @Override
    public TriggerResult onProcessingTime(long time, TimeWindow window, TriggerContext ctx)
            throws Exception {
        return TriggerResult.CONTINUE;
    }

    /**
     * Returns {@code true} to indicate that this trigger supports window merging (required for use
     * with {@link PricingSessionWindow}, which extends {@link
     * org.apache.flink.streaming.api.windowing.assigners.MergingWindowAssigner}).
     */
    @Override
    public boolean canMerge() {
        return true;
    }

    /**
     * Re-registers the end-of-session event-time timer for the merged window. Called when multiple
     * windows are merged into one by the assigner.
     */
    @Override
    public void onMerge(TimeWindow window, OnMergeContext ctx) {
        long windowMaxTimestamp = window.maxTimestamp();
        if (windowMaxTimestamp > ctx.getCurrentWatermark()) {
            ctx.registerEventTimeTimer(windowMaxTimestamp);
        }
    }

    /**
     * Cleans up the event-time timer registered for this window's end. Called when the window is
     * purged.
     */
    @Override
    public void clear(TimeWindow window, TriggerContext ctx) throws Exception {
        ctx.deleteEventTimeTimer(window.maxTimestamp());
    }

    @Override
    public String toString() {
        return "PricingSessionTrigger()";
    }
}

