package org.apache.flink.streaming.api.windowing.triggers;

import org.apache.flink.annotation.PublicEvolving;
import org.apache.flink.streaming.api.windowing.assigners.PricingSessionWindow;
import org.apache.flink.streaming.api.windowing.windows.TimeWindow;

/**
 * A {@link Trigger} for use with {@link PricingSessionWindow} that fires when the watermark passes
 * the end of the market session window (i.e., the configured market close time).
 *
 * <p>This trigger mirrors the behavior of {@link EventTimeTrigger} but is specialized for trading
 * session semantics:
 *
 * <ul>
 *   <li>Fires once at market close (window end) via an event-time timer.
 *   <li>Supports early firing when configured with an early-fire timestamp (e.g., a circuit-breaker
 *       halt signal sets an early timer via {@link #registerEarlyFire}).
 *   <li>Supports window merging ({@link #canMerge()} returns {@code true}) and re-registers timers
 *       on merge.
 *   <li>{@link #clear(TimeWindow, TriggerContext)} removes all registered event-time timers.
 * </ul>
 */
@PublicEvolving
public class PricingSessionTrigger extends Trigger<Object, TimeWindow> {

    private static final long serialVersionUID = 1L;

    private PricingSessionTrigger() {}

    /**
     * Creates a new {@code PricingSessionTrigger} that fires at the end of each session window.
     */
    public static PricingSessionTrigger create() {
        return new PricingSessionTrigger();
    }

    /**
     * Registers an early-fire event-time timer at the given timestamp. This can be used to trigger
     * early window evaluation on configurable events such as circuit-breaker halts.
     *
     * @param earlyFireTimestamp The event-time timestamp at which to fire early.
     * @param ctx The trigger context used to register the timer.
