     * an early-fire timer) also fires when its registered time is reached.
     */
    @Override
    public TriggerResult onEventTime(long time, TimeWindow window, TriggerContext ctx) {
        return time == window.maxTimestamp() ? TriggerResult.FIRE : TriggerResult.FIRE_AND_PURGE;
    }

    /** Processing-time timers are not used by this trigger. */
    @Override
    public TriggerResult onProcessingTime(long time, TimeWindow window, TriggerContext ctx)
            throws Exception {
        return TriggerResult.CONTINUE;
    }

    /**
     * Returns {@code true} to indicate that this trigger supports window merging (required for use
     * with {@link PricingSessionWindow}, which extends {@link
     * org.apache.flink.streaming.api.windowing.assigners.MergingWindowAssigner}).
     */
    @Override
    public boolean canMerge() {
        return true;
    }

    /**
     * Re-registers the end-of-session event-time timer for the merged window. Called when multiple
     * windows are merged into one by the assigner.
     */
    @Override
    public void onMerge(TimeWindow window, OnMergeContext ctx) {
        long windowMaxTimestamp = window.maxTimestamp();
        if (windowMaxTimestamp > ctx.getCurrentWatermark()) {
            ctx.registerEventTimeTimer(windowMaxTimestamp);
        }
    }

    /**
     * Cleans up the event-time timer registered for this window's end. Called when the window is
     * purged.
     */
    @Override
    public void clear(TimeWindow window, TriggerContext ctx) throws Exception {
        ctx.deleteEventTimeTimer(window.maxTimestamp());
    }

    @Override
    public String toString() {
        return "PricingSessionTrigger()";
    }
}
